import Fuse from 'fuse.js'
import { MakeLogicType, actions, connect, kea, listeners, path, reducers, selectors } from 'kea'

import { createFuse } from 'lib/utils/fuseSearch'
import { membersLogic } from 'scenes/organization/membersLogic'
import { rolesLogic } from 'scenes/settings/organization/Permissions/Roles/rolesLogic'

import type { RoleType } from '~/types'

import type { OrganizationMemberType } from '../../../../../frontend/src/types'
import { Assignee, TicketAssignee } from './types'

export interface RolesFuse extends Fuse<RoleType> {}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface assigneeSelectLogicValues {
    filteredMembers: OrganizationMemberType[] // membersLogic
    meFirstMembers: OrganizationMemberType[] // membersLogic
    membersLoading: boolean // membersLogic
    roles: RoleType[] // rolesLogic
    rolesLoading: boolean // rolesLogic
    filteredRoles: RoleType[]
    loading: boolean
    resolveAssignee: (assignee: TicketAssignee) => Assignee
    rolesFuse: RolesFuse
    search: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface assigneeSelectLogicActions {
    ensureAllMembersLoaded: () => {
        value: true
    } // membersLogic
    setMembersSearch: (search: any) => {
        search: any
    } // membersLogic
    ensureAssigneeTypesLoaded: () => {
        value: true
    }
    setSearch: (search: string) => {
        search: string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface assigneeSelectLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        loading: (membersLoading: boolean, rolesLoading: boolean) => boolean
        rolesFuse: (roles: RoleType[]) => RolesFuse
        filteredRoles: (roles: RoleType[], rolesFuse: RolesFuse, search: string) => RoleType[]
        resolveAssignee: (
            roles: RoleType[],
            meFirstMembers: OrganizationMemberType[]
        ) => (assignee: TicketAssignee) => Assignee
    }
}

export type assigneeSelectLogicType = MakeLogicType<
    assigneeSelectLogicValues,
    assigneeSelectLogicActions,
    Record<string, any>,
    assigneeSelectLogicMeta
>

export const assigneeSelectLogic = kea<assigneeSelectLogicType>([
    path(['products', 'conversations', 'frontend', 'components', 'Assignee', 'assigneeSelectLogic']),
    connect(() => ({
        values: [
            membersLogic,
            ['meFirstMembers', 'filteredMembers', 'membersLoading'],
            rolesLogic,
            ['roles', 'rolesLoading'],
        ],
        actions: [membersLogic, ['setSearch as setMembersSearch', 'ensureAllMembersLoaded']],
    })),
    actions({
        ensureAssigneeTypesLoaded: true,
        setSearch: (search: string) => ({ search }),
    }),
    reducers({
        search: ['', { setSearch: (_, { search }) => search }],
    }),
    listeners(({ values, actions }) => ({
        setSearch: () => {
            actions.setMembersSearch(values.search)
        },
        ensureAssigneeTypesLoaded: () => {
            actions.ensureAllMembersLoaded()
        },
    })),
    selectors({
        loading: [
            (s) => [s.membersLoading, s.rolesLoading],
            (membersLoading: boolean, rolesLoading: boolean): boolean => membersLoading || rolesLoading,
        ],

        rolesFuse: [
            (s) => [s.roles],
            (roles: RoleType[]): RolesFuse => createFuse<RoleType>(roles, { keys: ['name'], threshold: 0.3 }),
        ],

        filteredRoles: [
            (s) => [s.roles, s.rolesFuse, s.search],
            (roles: RoleType[], rolesFuse: RolesFuse, search: string): RoleType[] =>
                search ? rolesFuse.search(search).map((result) => result.item) : (roles ?? []),
        ],
        resolveAssignee: [
            (s) => [s.roles, s.meFirstMembers],
            (roles: RoleType[], members: OrganizationMemberType[]): ((assignee: TicketAssignee) => Assignee) => {
                return (assignee: TicketAssignee) => {
                    if (assignee) {
                        if (assignee.type === 'role') {
                            const assignedRole = roles.find((role) => String(role.id) === String(assignee.id))
                            return assignedRole
                                ? {
                                      id: assignedRole.id,
                                      type: 'role',
                                      role: assignedRole,
                                  }
                                : null
                        }

                        const assignedMember = members.find((member) => String(member.user.id) === String(assignee.id))
                        return assignedMember
                            ? {
                                  id: assignedMember.user.id,
                                  type: 'user',
                                  user: assignedMember.user,
                              }
                            : null
                    }

                    return null
                }
            },
        ],
    }),
])
